template.script:
            window.addEventListener('load', function () {
                const pageStyle = document.createElement('style');
                pageStyle.type = 'text/css';
                pageStyle.textContent =
                    '@page { margin: 0 !important; }' +
                    'html, body { margin: 0 !important; padding: 0 !important; }' +
                    'body { overflow: visible !important; }' +
                    '#stock-png-toolbar { position: fixed; top: 8px; right: 8px; z-index: 99999; display: flex; gap: 6px; }' +
                    '#stock-png-toolbar button { border: 1px solid #333; background: #fff; color: #111; padding: 6px 10px; font-size: 12px; cursor: pointer; }' +
                    '@media print { #stock-png-toolbar { display: none !important; } }';
                document.head.appendChild(pageStyle);

                const targets = Array.from(document.querySelectorAll('[data-png-canvas="1"]'));
                if (!targets.length) {
                    return;
                }

                const pngDataUrls = [];

                const downloadDataUrl = function (dataUrl, filename) {
                    const anchor = document.createElement('a');
                    anchor.href = dataUrl;
                    anchor.download = filename;
                    document.body.appendChild(anchor);
                    anchor.click();
                    anchor.remove();
                };

                const renderTarget = function (target) {
                    return new Promise(function (resolve) {
                        const rect = target.getBoundingClientRect();
                        const width = Math.ceil(Math.max(rect.width, target.scrollWidth || 0, target.offsetWidth || 0));
                        const height = Math.ceil(Math.max(rect.height, target.scrollHeight || 0, target.offsetHeight || 0));

                        if (!width || !height) {
                            resolve();
                            return;
                        }

                        const clone = target.cloneNode(true);
                        clone.removeAttribute('data-png-canvas');
                        clone.style.margin = '0';
                        clone.style.boxSizing = 'border-box';

                        const svg =
                            '' +
                            '' +
                            '
' +
                            clone.outerHTML +
                            '' +
                            '' +
                            '';

                        const svgBlob = new Blob([svg], { type: 'image/svg+xml;charset=utf-8' });
                        const svgUrl = URL.createObjectURL(svgBlob);
                        const image = new Image();

                        image.onload = function () {
                            const canvas = document.createElement('canvas');
                            const scale = 2;
                            canvas.width = width * scale;
                            canvas.height = height * scale;

                            const context = canvas.getContext('2d');
                            context.scale(scale, scale);
                            context.drawImage(image, 0, 0);

                            URL.revokeObjectURL(svgUrl);

                            const dataUrl = canvas.toDataURL('image/png');
                            pngDataUrls.push(dataUrl);

                            const pngImage = document.createElement('img');
                            pngImage.src = dataUrl;
                            pngImage.alt = 'Printable label PNG';
                            pngImage.style.display = 'block';
                            pngImage.style.width = width + 'px';
                            pngImage.style.height = height + 'px';
                            pngImage.style.margin = '0';
                            pngImage.style.padding = '0';

                            const wrapper = document.createElement('div');
                            wrapper.style.margin = '0';
                            wrapper.style.padding = '0';
                            wrapper.style.width = width + 'px';
                            wrapper.style.height = height + 'px';
                            wrapper.style.overflow = 'hidden';
                            wrapper.style.position = 'relative';
                            wrapper.style.pageBreakAfter = 'always';
                            wrapper.appendChild(pngImage);

                            target.replaceWith(wrapper);
                            resolve();
                        };

                        image.onerror = function () {
                            URL.revokeObjectURL(svgUrl);
                            resolve();
                        };

                        image.src = svgUrl;
                    });
                };

                (async function () {
                    for (const target of targets) {
                        await renderTarget(target);
                    }

                    if (pngDataUrls.length) {
                        const toolbar = document.createElement('div');
                        toolbar.id = 'stock-png-toolbar';

                        const downloadBtn = document.createElement('button');
                        downloadBtn.type = 'button';
                        downloadBtn.textContent = pngDataUrls.length === 1 ? 'Download PNG' : 'Download PNGs';
                        downloadBtn.addEventListener('click', function () {
                            if (pngDataUrls.length === 1) {
                                downloadDataUrl(pngDataUrls[0], 'label.png');
                                return;
                            }
                            pngDataUrls.forEach(function (dataUrl, idx) {
                                setTimeout(function () {
                                    downloadDataUrl(dataUrl, 'label-' + (idx + 1) + '.png');
                                }, idx * 250);
                            });
                        });

                        const printBtn = document.createElement('button');
                        printBtn.type = 'button';
                        printBtn.textContent = 'Print';
                        printBtn.addEventListener('click', function () {
                            window.focus();
                            window.print();
                        });

                        toolbar.appendChild(downloadBtn);
                        toolbar.appendChild(printBtn);
                        document.body.appendChild(toolbar);
                    }

                    document.body.style.margin = '0';
                    document.body.style.padding = '0';
                    window.focus();
                    window.print();
                })();
            });
